PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?margin
WHERE {
  ?match wdt:P3487 wd:Q10940148 ;
         wdt:P1545 wd:Q10508, wd:Q21844 ;
         wdt:P6593 ?homeScore ;
         wdt:P6594 ?awayScore .
  BIND(ABS(?homeScore - ?awayScore) AS ?margin)
